import React from 'react';
import { Link } from 'react-scroll';
import { motion } from 'framer-motion';
import { Typewriter } from 'react-simple-typewriter';
import { FiGithub, FiLinkedin, FiMail, FiDownload } from 'react-icons/fi';
import './Hero.css';

const Hero = ({ profile }) => {
  const downloadResume = async () => {
    try {
      const res = await fetch(`${process.env.PUBLIC_URL}/documents/resume.pdf`);
      const blob = await res.blob();
      const url = window.URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = 'Syed_Roohan_Ali_Rizvi_Resume.pdf';
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      window.URL.revokeObjectURL(url);
    } catch (err) {
      window.open(`${process.env.PUBLIC_URL}/documents/resume.pdf`, '_blank');
    }
  };

  const taglines = [
    "AI & Machine Learning Enthusiast",
    "Full-Stack Developer",
    "Building Intelligent Solutions",
    "Computer Vision Explorer"
  ];

  return (
    <motion.section
      id="hero"
      className="hero"
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      transition={{ duration: 0.8 }}
    >
      <div className="hero-overlay"></div>
      <div className="hero-content">
        <motion.div
          className="hero-text"
          initial={{ opacity: 0, x: -50 }}
          animate={{ opacity: 1, x: 0 }}
          transition={{ duration: 0.8, delay: 0.2 }}
        >
          <p className="hero-greeting">Hello, I'm</p>
          <h1 className="hero-name">{profile.name}</h1>
          <h2 className="hero-title">
            <Typewriter
              words={taglines}
              loop={0}
              cursor
              cursorStyle="|"
              typeSpeed={70}
              deleteSpeed={40}
              delaySpeed={1500}
            />
          </h2>
          <p className="hero-tagline">{profile.tagline}</p>
          <div className="hero-actions">
            <Link to="projects" smooth={true} duration={500} className="btn btn-primary">
              View My Work
            </Link>
            <a href={profile.github} target="_blank" rel="noopener noreferrer" className="btn btn-outline">
              GitHub
            </a>
            <button onClick={downloadResume} className="btn btn-outline">
              <FiDownload /> Resume
            </button>
          </div>
          <div className="hero-socials">
            <a href={profile.github} target="_blank" rel="noopener noreferrer" aria-label="GitHub">
              <FiGithub />
            </a>
            <a href={profile.linkedin} target="_blank" rel="noopener noreferrer" aria-label="LinkedIn">
              <FiLinkedin />
            </a>
            <a href={`mailto:${profile.email}`} aria-label="Email">
              <FiMail />
            </a>
          </div>
        </motion.div>
      </div>
    </motion.section>
  );
};

export default Hero;
